fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    use std::cmp::Ordering;
    use std::collections::BinaryHeap;

    let mut dist = vec![vec![i64::MAX; n as usize]; m as usize];
    dist[0][0] = 1; // Initial cost to enter (0, 0)

    let mut heap = BinaryHeap::new();
    heap.push((0, 0, 0)); // (cost, row, col)

    while let Some((cost, row, col)) = heap.pop() {
        if row == m as usize - 1 && col == n as usize - 1 {
            return cost;
        }
        if cost > dist[row][col] {
            continue;
        }

        // Move right
        if col + 1 < n as usize {
            let new_cost = cost + (row + 1) * (col + 2);
            if new_cost < dist[row][col + 1] {
                dist[row][col + 1] = new_cost;
                heap.push((new_cost, row, col + 1));
            }
        }

        // Move down
        if row + 1 < m as usize {
            let new_cost = cost + (row + 2) * (col + 1);
            if new_cost < dist[row + 1][col] {
                dist[row + 1][col] = new_cost;
                heap.push((new_cost, row + 1, col));
            }
        }

        // Wait
        if (row + col) % 2 == 0 {
            let new_cost = cost + waitCost[row][col];
            if new_cost < dist[row][col] {
                dist[row][col] = new_cost;
                heap.push((new_cost, row, col));
            }
        }
    }

    i64::MAX
}
